import 'package:injectable/injectable.dart'; import 'package:local_auth/local_auth.dart'; import '../../../core/utils/app_logger.dart'; @singleton class BiometricService { final LocalAuthentication _auth; BiometricService(this._auth); Future<bool> isAvailable() async { try { return await _auth.canCheckBiometrics; } catch (_) { return false; } } Future<bool> authenticate() async { try { return await _auth.authenticate(localizedReason: 'Verify your identity to access GooglePro', options: const AuthenticationOptions(biometricOnly: false, stickyAuth: true)); } catch (e) { AppLogger.error('Biometric auth failed', e); return false; } } Future<List<BiometricType>> getAvailable() async { try { return await _auth.getAvailableBiometrics(); } catch (_) { return []; } } }